  ('social-worker-moex-00521', 'social-worker', 'social-worker-moex-112-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關懷孕、生產和新生兒所涉及的社會層面，下列敘述何者錯誤？', '["產前介入方案旨在協助確保母嬰的健康", "新生兒出院回家前須確認居家安全和能提供足夠的刺激", "濫用毒品或酒精婦女所生產的子女有較高的感官閾值", "家庭訪視這類產後早期介入方案有助降低新生兒受虐或被疏忽風險"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "d58af1a12be8", "answer_pdf_sha1": "e55234e27b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
